"""
Test Cases Template - 1000 generated test cases
Mix of GTGT (Vietnamese VAT) and Commercial invoice patterns
Generated based on patterns from test_cases_commercial.py and test_cases_gtgt.py
"""
import sys, os, json
sys.path.insert(0, os.path.join(os.path.dirname(os.path.abspath(__file__)), ".."))

from src.parsers.block_invoice_parser import parse_invoice_block_based
from src.parsers.block_invoice_zoomtext_parser import parse_zoom_header
from datetime import date as date_type


def normalize_date(val):
    if isinstance(val, date_type):
        return val.strftime("%d/%m/%Y")
    if isinstance(val, str) and "-" in val:
        p = val.split("-")
        if len(p) == 3:
            return f"{p[2]}/{p[1]}/{p[0]}"
    return val


def run_case(case_id, filename, raw_text, zoom_text):
    invoice = parse_invoice_block_based(raw_text)
    if zoom_text and zoom_text.strip():
        zoom_lines = zoom_text.splitlines()
        parse_zoom_header(zoom_lines, invoice)
    d = invoice.model_dump()
    if d.get("invoiceDate"):
        d["invoiceDate"] = normalize_date(d["invoiceDate"])
    return d


ALL_FIELDS = [
    # Invoice info
    "invoiceName", "invoiceID", "invoiceDate", "invoiceSerial",
    "invoiceFormNo", "paymentMethod", "currency",
    # Seller
    "sellerName", "sellerTaxCode", "sellerEmail",
    "sellerAddress", "sellerPhoneNumber", "sellerBank", "sellerBankAccountNumber",
    # Buyer
    "buyerName", "buyerTaxCode", "buyerEmail",
    "buyerAddress", "buyerPhoneNumber", "buyerBank", "buyerBankAccountNumber",
    # Amount
    "preTaxPrice", "discountTotal", "taxPercent", "taxAmount",
    "totalAmount", "invoiceTotalInWord",
]


def print_result(case_id, filename, d):
    null_count = sum(1 for f in ALL_FIELDS if d.get(f) is None)
    ok_count = len(ALL_FIELDS) - null_count

    print(f"\n{'='*80}")
    print(f"[{case_id:04d}] {filename}  ({ok_count}/{len(ALL_FIELDS)} fields)")
    print(f"{'='*80}")

    json_output = {k: d.get(k) for k in ALL_FIELDS}
    print(json.dumps(json_output, ensure_ascii=False, indent=2))

    null_fields = [f for f in ALL_FIELDS if d.get(f) is None]
    if null_fields:
        print(f"\n  \u274c NULL: {', '.join(null_fields)}")
    else:
        print(f"\n  \u2705 All fields populated!")

    items = d.get("itemList", []) or []
    item_count = len(items)
    if item_count > 0:
        print(f"\n  \U0001f4e6 itemList: {item_count} items")
        for i, item in enumerate(items[:5]):
            name = (item.get('productName') or '-')[:40]
            unit = item.get('unit') or '-'
            qty = item.get('quantity', '-')
            price = item.get('unitPrice', '-')
            amt = item.get('amount', '-')
            print(f"    [{i+1}] {name} | unit={unit} | qty={qty} | price={price} | amt={amt}")
        if item_count > 5:
            print(f"    ... +{item_count - 5} more")
    else:
        print(f"\n  \u26a0\ufe0f  itemList: EMPTY")

    return ok_count, item_count


